using System.IO.Compression;
using System.Text;

class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now defaults to UTF-8 with the
        // EFS flag set. The legacy Java consumer expects Shift-JIS filenames,
        // so pass the encoding explicitly to suppress the EFS flag.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");

        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: keyed and non-keyed registrations are
// strictly separated. A [FromKeyedServices("cache")] parameter can
// no longer fall back to a non-keyed registration.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

